/// <summary>
/// Creates an unsold inventory transaction.
/// </summary>
/// <param name="_inventTrans">The original inventory transaction.</param>
/// <param name="_inventDimId">The inventory dimension ID (optional).</param>
/// <returns>Returns the created unsold inventory transaction.</returns>
public static InventTrans ETGSPAINcreateUnsoldInventTrans(InventTrans _inventTrans,
                                                            InventDimId _inventDimId = "")
{
    InventTrans         inventTransCreated;

    inventTransCreated.clear();
    buf2Buf(_inventTrans, inventTransCreated);

    inventTransCreated.StatusIssue                  = StatusIssue::None;
    inventTransCreated.StatusReceipt                = StatusReceipt::None;
    inventTransCreated.ETGSPAINInventTransIsUnsold  = NoYes::Yes;

    inventTransCreated.inventDimId = _inventDimId ? _inventDimId : inventTransCreated.inventDimId;

    inventTransCreated.Qty                          = 0;

    inventTransCreated.insert();

    return inventTransCreated;
}
